import json, urllib.request
metrics={'requests':0,'tokens':0,'errors':0}
for p in ['playbook reuse','kg adapt','experience graph']:
    data=json.dumps({'model':'gemma3:4b','prompt':'Define '+p+' in 6 words','stream':False,'options':{'num_predict':12}}).encode()
    req=urllib.request.Request('http://211.170.162.139:10934/api/generate',data=data,headers={'Content-Type':'application/json'})
    try:
        r=json.loads(urllib.request.urlopen(req).read())
        metrics['requests']+=1
        metrics['tokens']+=r.get('eval_count',0)
    except Exception as e:
        metrics['errors']+=1
print('=== KG Monitoring ===')
for k,v in metrics.items():
    print(f' {k}: {v}')
